#Context: In order to know how many base pairs do you need to change in one string to make it exactly like the other, 
#you calculate every base that does not match the letter in the same place in the other string

def hamming(s1, s2):
    distance=0
    for i in range(0, len(s1)-1):
        if s1[i:i+1]!=s2[i:i+1]:
            distance+=1

    return distance



print(hamming("",""))

